const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, Footer, Header
} = require('docx');
const fs = require('fs');

const DARK = "1A1A2E";
const ACCENT = "E94560";
const ACCENT2 = "0F3460";
const LIGHT_BG = "F0F4FF";
const GRAY = "666666";
const WHITE = "FFFFFF";
const LIGHT_ACCENT = "FFE8EC";

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 400, after: 200 },
    children: [new TextRun({ text, bold: true, size: 36, color: WHITE, font: "Arial" })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 300, after: 150 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: ACCENT, space: 1 } },
    children: [new TextRun({ text, bold: true, size: 28, color: ACCENT2, font: "Arial" })]
  });
}

function h3(text) {
  return new Paragraph({
    spacing: { before: 200, after: 100 },
    children: [new TextRun({ text, bold: true, size: 24, color: DARK, font: "Arial" })]
  });
}

function body(text, options = {}) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    children: [new TextRun({ text, size: 22, color: options.color || "333333", font: "Arial", bold: options.bold || false, italics: options.italic || false })]
  });
}

function bullet(text, bold_part = null) {
  const children = [];
  if (bold_part) {
    children.push(new TextRun({ text: bold_part + " ", size: 22, color: DARK, font: "Arial", bold: true }));
    children.push(new TextRun({ text, size: 22, color: "333333", font: "Arial" }));
  } else {
    children.push(new TextRun({ text: "→  " + text, size: 22, color: "333333", font: "Arial" }));
  }
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    indent: { left: 400 },
    children
  });
}

function warningBox(text) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: LIGHT_ACCENT, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            children: [new Paragraph({
              children: [
                new TextRun({ text: "⚠  ", size: 22, bold: true, color: ACCENT, font: "Arial" }),
                new TextRun({ text, size: 22, color: DARK, font: "Arial", italics: true })
              ]
            })]
          })
        ]
      })
    ]
  });
}

function infoBox(text) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: LIGHT_BG, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            children: [new Paragraph({
              children: [
                new TextRun({ text: "✅  ", size: 22, bold: true, color: "2E7D32", font: "Arial" }),
                new TextRun({ text, size: 22, color: DARK, font: "Arial" })
              ]
            })]
          })
        ]
      })
    ]
  });
}

function codeBox(lines) {
  const children = lines.map(line =>
    new Paragraph({
      spacing: { before: 40, after: 40 },
      children: [new TextRun({ text: line, size: 18, font: "Courier New", color: "D4E6F1" })]
    })
  );
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: "1E2A3A", type: ShadingType.CLEAR },
            margins: { top: 160, bottom: 160, left: 240, right: 240 },
            children
          })
        ]
      })
    ]
  });
}

function headerBanner(title, subtitle) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: DARK, type: ShadingType.CLEAR },
            margins: { top: 400, bottom: 400, left: 400, right: 400 },
            children: [
              new Paragraph({
                alignment: AlignmentType.CENTER,
                children: [new TextRun({ text: title, size: 52, bold: true, color: WHITE, font: "Arial" })]
              }),
              new Paragraph({
                alignment: AlignmentType.CENTER,
                spacing: { before: 120 },
                children: [new TextRun({ text: subtitle, size: 24, color: "AAAACC", font: "Arial", italics: true })]
              })
            ]
          })
        ]
      })
    ]
  });
}

function stepBox(num, title, desc) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [800, 8560],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: 800, type: WidthType.DXA },
            shading: { fill: ACCENT, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 120, right: 120 },
            verticalAlign: "center",
            children: [new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: num, size: 32, bold: true, color: WHITE, font: "Arial" })]
            })]
          }),
          new TableCell({
            borders: noBorders,
            width: { size: 8560, type: WidthType.DXA },
            shading: { fill: LIGHT_BG, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            children: [
              new Paragraph({ children: [new TextRun({ text: title, size: 22, bold: true, color: DARK, font: "Arial" })] }),
              new Paragraph({ children: [new TextRun({ text: desc, size: 20, color: GRAY, font: "Arial" })] })
            ]
          })
        ]
      })
    ]
  });
}

function space(n = 1) {
  return Array(n).fill(new Paragraph({ children: [new TextRun({ text: "" })] }));
}

const doc = new Document({
  numbering: { config: [] },
  styles: {
    default: { document: { run: { font: "Arial", size: 22 } } },
    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 36, bold: true, font: "Arial", color: WHITE },
        paragraph: { spacing: { before: 400, after: 200 }, outlineLevel: 0 } },
      { id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Arial", color: ACCENT2 },
        paragraph: { spacing: { before: 300, after: 150 }, outlineLevel: 1 } },
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 12240, height: 15840 },
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 }
      }
    },
    children: [

      // HEADER BANNER
      headerBanner(
        "PROMPT MAESTRO",
        "Desarrollo de Estrategias de Trading Cuantitativo desde Cero"
      ),
      ...space(2),

      // SECCION 1 — CONTEXTO
      h2("1.  IDENTIDAD Y CONTEXTO DEL ASISTENTE"),
      ...space(),
      body("Eres un experto en trading cuantitativo, estadística financiera y programación MQL5. Tienes experiencia comprobada desarrollando EAs (Expert Advisors) rentables para MetaTrader 5, incluyendo estrategias ORB, VWAP, breakout y scalping. Tu metodología es rigurosa, honesta y basada en evidencia estadística real."),
      ...space(),
      body("Has trabajado conmigo anteriormente en dos EAs rentables:", { bold: true }),
      bullet("EA BreakoutNY — NAS100, sesión NY, estrategia ORB + VWAP + PDH/PDL"),
      bullet("EA Scalping XAUUSD — sesión NY, M5, análisis estadístico del activo"),
      ...space(2),

      // SECCION 2 — REGLAS CRITICAS
      h2("2.  REGLAS CRÍTICAS DE HONESTIDAD (No Negociables)"),
      ...space(),
      warningBox("Nunca concluyas que una estrategia 'tiene potencial' basándote solo en estadísticas descriptivas del pasado. Exige evidencia de edge real antes de proceder."),
      ...space(),
      h3("2.1  Análisis de CSV — Cómo interpretar datos reales"),
      body("Cuando el usuario te pase un archivo CSV con datos reales del activo (generado por un script MQL5):"),
      bullet("Muestra las estadísticas CRUDAS primero — sin interpretación favorable"),
      bullet("Identifica explícitamente las DEBILIDADES antes que las fortalezas"),
      bullet("Si los datos no soportan una estrategia rentable, dilo directamente: 'Estos datos NO son suficientes para una estrategia viable'"),
      bullet("Nunca infles expectativas con frases como 'tiene buen potencial' sin datos duros que lo respalden"),
      ...space(),
      h3("2.2  Umbral mínimo antes de escribir código"),
      infoBox("NO se escribe ni una línea de EA hasta que los datos demuestren los siguientes criterios mínimos."),
      ...space(),
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [3000, 3680, 2680],
        rows: [
          new TableRow({
            children: [
              new TableCell({ borders, width: { size: 3000, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Criterio", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
              new TableCell({ borders, width: { size: 3680, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Valor Mínimo", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
              new TableCell({ borders, width: { size: 2680, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Nota", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
            ]
          }),
          ...[
            ["Win Rate (lógica de entrada)", "> 50%", "O RR que lo compense"],
            ["Edge estadístico direccional", "Verificable en datos", "No solo 'hay movimiento'"],
            ["Viabilidad post spread/comisión", "Profit neto positivo", "Calcular con datos reales"],
            ["Tamaño de muestra", "> 200 operaciones", "Para validez estadística"],
          ].map((row, i) => new TableRow({
            children: row.map((cell, j) => new TableCell({
              borders,
              width: { size: [3000, 3680, 2680][j], type: WidthType.DXA },
              shading: { fill: i % 2 === 0 ? "FFFFFF" : LIGHT_BG, type: ShadingType.CLEAR },
              margins: { top: 80, bottom: 80, left: 120, right: 120 },
              children: [new Paragraph({ children: [new TextRun({ text: cell, size: 20, color: DARK, font: "Arial" })] })]
            }))
          }))
        ]
      }),
      ...space(2),

      // SECCION 3 — PROCESO
      h2("3.  PROCESO METODOLÓGICO PASO A PASO"),
      ...space(),
      body("Seguir este proceso en orden estricto. No saltar pasos.", { bold: true }),
      ...space(),

      stepBox("1", "Definir activo y sesión", "Elegir el par, timeframe y ventana horaria antes de cualquier análisis. El activo debe tener características conocidas: liquidez, volatilidad, sesgo estructural."),
      ...space(),
      stepBox("2", "Script MQL5 de análisis estadístico", "Crear un script que extraiga datos reales del activo desde MT5 y los exporte a CSV. El script debe medir: distribución de retornos por hora, volatilidad promedio, comportamiento en horas clave, win rate de movimientos direccionales simples."),
      ...space(),
      stepBox("3", "Análisis honesto del CSV", "El usuario ejecuta el script en MT5 y pasa el CSV. Claude analiza los datos reales con los criterios de la Sección 2.1. Veredicto obligatorio: VIABLE o NO VIABLE antes de continuar."),
      ...space(),
      stepBox("4", "Diseño de lógica de entrada (solo si VIABLE)", "Traducir el edge estadístico encontrado en reglas de entrada/salida concretas. Empezar con la lógica MÁS SIMPLE posible. Documentar exactamente qué patrón estadístico justifica cada regla."),
      ...space(),
      stepBox("5", "EA mínimo viable (sin módulos extra)", "Codificar SOLO la lógica core: entrada, SL, TP, gestión de lote básica. Sin dashboard, sin trailing dinámico, sin filtros de noticias. El objetivo es verificar que la lógica base funciona."),
      ...space(),
      stepBox("6", "Backtest y diagnóstico", "El usuario corre el backtest en MT5 y reporta resultados. Claude diagnostica antes de agregar complejidad. Si el backtest falla, se vuelve al Paso 4 — NO se agregan módulos para 'compensar'."),
      ...space(),
      stepBox("7", "Walk-forward validation", "Una vez que el EA base es rentable en in-sample, validar en out-of-sample (30% de datos no vistos). Si falla aquí, el edge no es real."),
      ...space(),
      stepBox("8", "Módulos adicionales (solo si Walk-forward pasa)", "Agregar trailing stop, dashboard, filtro de noticias, etc. Cada módulo se agrega de uno en uno y se verifica que no destruye el edge."),
      ...space(2),

      // SECCION 4 — ANTI-PATRONES
      h2("4.  ANTI-PATRONES PROHIBIDOS"),
      ...space(),
      warningBox("Estos son los errores que han causado EAs no rentables en el pasado. Claude debe evitarlos activamente y alertar al usuario cuando los detecte."),
      ...space(),

      h3("4.1  Data Snooping / Mining Bias"),
      body("Probar cientos de combinaciones de parámetros y quedarse con la mejor es overfitting, no un edge real. El parámetro correcto no es el que maximiza el profit en backtest — es el que funciona en un rango amplio de valores."),
      ...space(),
      infoBox("Test de robustez: si ATR(14) funciona pero ATR(12) y ATR(16) no, es overfitting. Un edge real funciona en ±20% del valor óptimo."),
      ...space(),

      h3("4.2  Optimismo prematuro"),
      body("Frases prohibidas antes de verificar con datos reales:"),
      bullet('"Este activo tiene buenas condiciones para scalping"'),
      bullet('"La estrategia tiene buen potencial"'),
      bullet('"Con ajustes debería mejorar"'),
      ...space(),

      h3("4.3  Agregar complejidad para compensar un edge débil"),
      body("Si la lógica base no es rentable, agregar un trailing ATR dinámico o un filtro de noticias no lo arreglará. Complejidad sobre un edge inexistente = pérdidas más sofisticadas."),
      ...space(),

      h3("4.4  Ignorar el sesgo estructural del activo"),
      body("Ejemplo aprendido: NAS100 tiene sesgo alcista secular. Operar SHORTs contra esa tendencia produce edge negativo sistémico. Siempre verificar el sesgo del activo antes de permitir operaciones en ambas direcciones."),
      ...space(2),

      // SECCION 5 — METRICAS
      h2("5.  MÉTRICAS DE EVALUACIÓN CORRECTAS"),
      ...space(),
      body("No mirar solo el profit total. Las métricas que importan:", { bold: true }),
      ...space(),
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [3000, 2000, 4360],
        rows: [
          new TableRow({
            children: [
              new TableCell({ borders, width: { size: 3000, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Métrica", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
              new TableCell({ borders, width: { size: 2000, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Umbral Mínimo", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
              new TableCell({ borders, width: { size: 4360, type: WidthType.DXA }, shading: { fill: ACCENT2, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 },
                children: [new Paragraph({ children: [new TextRun({ text: "Por qué importa", size: 20, bold: true, color: WHITE, font: "Arial" })] })] }),
            ]
          }),
          ...[
            ["Profit Factor", "> 1.5", "Ratio ganancia/pérdida bruta. < 1.3 es frágil."],
            ["Sharpe Ratio", "> 1.0", "Retorno ajustado por riesgo"],
            ["Max Drawdown", "< 10% cuenta", "Límite para Prop Firms"],
            ["Consistencia mensual", "> 70% meses positivos", "Edge real vs suerte"],
            ["Win Rate con RR real", "Coherente con RR neto", "Incluir spread + comisión"],
          ].map((row, i) => new TableRow({
            children: row.map((cell, j) => new TableCell({
              borders,
              width: { size: [3000, 2000, 4360][j], type: WidthType.DXA },
              shading: { fill: i % 2 === 0 ? "FFFFFF" : LIGHT_BG, type: ShadingType.CLEAR },
              margins: { top: 80, bottom: 80, left: 120, right: 120 },
              children: [new Paragraph({ children: [new TextRun({ text: cell, size: 20, color: DARK, font: "Arial" })] })]
            }))
          }))
        ]
      }),
      ...space(2),

      // SECCION 6 — PROMPT DE ARRANQUE
      h2("6.  PROMPT DE ARRANQUE — Copiar y Pegar"),
      ...space(),
      body("Usar este bloque al inicio de cada nueva conversación de estrategia:", { bold: true }),
      ...space(),
      codeBox([
        "Eres un experto en trading cuantitativo y MQL5. Vamos a desarrollar una",
        "estrategia desde cero siguiendo el Prompt Maestro v1.0.",
        "",
        "REGLAS OBLIGATORIAS:",
        "1. No concluyas viabilidad sin datos reales del CSV.",
        "2. No escribas código de EA hasta verificar edge estadístico.",
        "3. Muestra debilidades antes que fortalezas en el análisis.",
        "4. Si el backtest falla, diagnostica antes de agregar complejidad.",
        "5. Valida siempre en out-of-sample antes de agregar módulos.",
        "",
        "ACTIVO: [Indicar par — ej. XAUUSD / NAS100 / EURUSD]",
        "SESIÓN: [Indicar — ej. NY / Londres / Asian]",
        "TIMEFRAME: [Indicar — ej. M5 / M15 / H1]",
        "CUENTA: [Indicar capital y % de riesgo por operación]",
        "BROKER: [Indicar broker y offset UTC del servidor]",
        "",
        "Comienza con el Paso 1: genera el script MQL5 de análisis estadístico.",
      ]),
      ...space(2),

      // SECCION 7 — CHECKLIST
      h2("7.  CHECKLIST DE VALIDACIÓN FINAL"),
      ...space(),
      body("Antes de considerar un EA 'listo para forward test', verificar todos los puntos:"),
      ...space(),
      ...[
        "Edge estadístico verificado en datos reales (CSV analizado)",
        "Lógica base rentable en backtest in-sample (Profit Factor > 1.5)",
        "Walk-forward validation pasada (out-of-sample rentable)",
        "Spread y comisión calculados en el RR real (no teórico)",
        "Sesgo del activo identificado (solo operar en dirección del sesgo si aplica)",
        "Test de robustez de parámetros (±20% del valor óptimo sigue siendo rentable)",
        "Máximo drawdown dentro del límite de la cuenta / Prop Firm",
        "EA probado en modo visual en MT5 para verificar entradas/salidas correctas",
      ].map(item => new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [600, 8760],
        rows: [new TableRow({
          children: [
            new TableCell({ borders: noBorders, width: { size: 600, type: WidthType.DXA }, shading: { fill: "F9F9F9", type: ShadingType.CLEAR }, margins: { top: 60, bottom: 60, left: 120, right: 0 },
              children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "☐", size: 24, color: ACCENT, font: "Arial" })] })] }),
            new TableCell({ borders: noBorders, width: { size: 8760, type: WidthType.DXA }, shading: { fill: "F9F9F9", type: ShadingType.CLEAR }, margins: { top: 60, bottom: 60, left: 120, right: 120 },
              children: [new Paragraph({ children: [new TextRun({ text: item, size: 20, color: DARK, font: "Arial" })] })] }),
          ]
        })]
      })).flatMap(t => [t, ...space()]),

      ...space(),
      // FOOTER NOTE
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [9360],
        rows: [new TableRow({
          children: [new TableCell({
            borders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: DARK, type: ShadingType.CLEAR },
            margins: { top: 160, bottom: 160, left: 240, right: 240 },
            children: [new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "PROMPT MAESTRO v1.0  —  Generado con Claude Sonnet 4.6  —  Marzo 2026", size: 18, color: "AAAACC", font: "Arial", italics: true })]
            })]
          })]
        })]
      }),
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("/mnt/user-data/outputs/Prompt_Maestro_Trading_Cuantitativo.docx", buffer);
  console.log("✅ Documento creado exitosamente");
}).catch(err => console.error("Error:", err));

