// ── BORDER HELPERS ─────────────────────────────────────────────
const b1 = (color = C.border) => ({ style: BorderStyle.SINGLE, size: 1, color });
const bAll = (color = C.border) => ({ top: b1(color), bottom: b1(color), left: b1(color), right: b1(color) });
const bNone = () => ({ top: b1("FFFFFF"), bottom: b1("FFFFFF"), left: b1("FFFFFF"), right: b1("FFFFFF") });

// ── TEXT HELPERS ───────────────────────────────────────────────
const run = (text, opts = {}) => new TextRun({
  text, font: "Arial",
  size:    opts.size    || 20,
  bold:    opts.bold    || false,
  italics: opts.italic  || false,
  color:   opts.color   || C.text,
  highlight: opts.highlight || undefined,
});

const monoRun = (text, opts = {}) => new TextRun({
  text, font: "Courier New",
  size:  opts.size  || 18,
  color: opts.color || "58A6FF",
  bold:  opts.bold  || false,
});

// ── PARAGRAPH HELPERS ──────────────────────────────────────────
const sp = (n = 1) => Array(n).fill(new Paragraph({ children: [run("")] }));

const para = (children, opts = {}) => new Paragraph({
  alignment: opts.align || AlignmentType.LEFT,
  spacing:   { before: opts.before || 80, after: opts.after || 80 },
  indent:    opts.indent ? { left: opts.indent } : undefined,
  border:    opts.border || undefined,
  children:  Array.isArray(children) ? children : [children],
});

const h1 = (text) => new Paragraph({
  heading: HeadingLevel.HEADING_1,
  spacing: { before: 480, after: 240 },
  children: [run(text, { size: 32, bold: true, color: C.dark })],
  border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: C.accent, space: 2 } },
});

const h2 = (text) => new Paragraph({
  heading: HeadingLevel.HEADING_2,
  spacing: { before: 320, after: 160 },
  children: [run(text, { size: 26, bold: true, color: C.dark })],
  border: { bottom: { style: BorderStyle.SINGLE, size: 3, color: C.border, space: 1 } },
});

const h3 = (text) => new Paragraph({
  spacing: { before: 240, after: 120 },
  children: [run(text, { size: 22, bold: true, color: C.dark })],
});

const h4 = (text, color = C.muted) => new Paragraph({
  spacing: { before: 160, after: 80 },
  children: [run(text, { size: 20, bold: true, color })],
});

const body = (text, opts = {}) => para(
  run(text, { size: 20, color: opts.color || C.text, bold: opts.bold || false, italic: opts.italic || false }),
  { before: 60, after: 60, indent: opts.indent }
);

const bullet = (children, level = 0) => new Paragraph({
  spacing: { before: 60, after: 60 },
  indent: { left: 360 + level * 280, hanging: 200 },
  children: [
    run("▸  ", { color: C.accent, bold: true, size: 20 }),
    ...(Array.isArray(children) ? children : [run(children, { size: 20 })]),
  ],
});

const numbered = (num, children) => new Paragraph({
  spacing: { before: 80, after: 80 },
  indent: { left: 400, hanging: 240 },
  children: [
    run(`${num}.  `, { color: C.accent, bold: true, size: 20 }),
