// ── TABLE BUILDER ──────────────────────────────────────────────
const makeTable = (headers, rows, colWidths) => {
  const totalW = colWidths.reduce((a, b) => a + b, 0);
  const headerRow = new TableRow({ children: headers.map((h, i) =>
    new TableCell({
      borders: bAll(C.accent),
      width: { size: colWidths[i], type: WidthType.DXA },
      shading: { fill: C.dark, type: ShadingType.CLEAR },
      margins: { top: 100, bottom: 100, left: 140, right: 140 },
      children: [new Paragraph({ children: [run(h, { bold: true, color: C.white, size: 19 })] })],
    })
  )});
  const dataRows = rows.map((row, ri) => new TableRow({ children: row.map((cell, ci) =>
    new TableCell({
      borders: bAll(),
      width: { size: colWidths[ci], type: WidthType.DXA },
      shading: { fill: ri % 2 === 0 ? C.row_white : C.row_alt, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 140, right: 140 },
      children: [new Paragraph({ children: Array.isArray(cell)
        ? cell
        : [run(cell, { size: 19 })] })],
    })
  )}));
  return new Table({ width: { size: totalW, type: WidthType.DXA }, columnWidths: colWidths, rows: [headerRow, ...dataRows] });
};

