      bullet([run("Hora del servidor:", { bold: true, size: 20 }), run(" Usar offset manual (InpBrokerGMT) para compatibilidad con backtesting. TimeGMT() no funciona en Strategy Tester.", { size: 20 })]),
      bullet([run("Validación de stops:", { bold: true, size: 20 }), run(" Siempre verificar SYMBOL_TRADE_STOPS_LEVEL y SYMBOL_TRADE_FREEZE_LEVEL antes de modificar posiciones.", { size: 20 })]),
      bullet([run("Magic Number:", { bold: true, size: 20 }), run(" Único por EA y símbolo. Filtrar todas las operaciones por MagicNumber para evitar interferencia.", { size: 20 })]),
      bullet([run("OnTradeTransaction vs polling:", { bold: true, size: 20 }), run(" OnTradeTransaction NO funciona en backtesting. Usar HistorySelect() en polling para detectar cierres.", { size: 20 })]),
      ...sp(),

      h3("6.3  Bugs comunes y cómo evitarlos"),
      makeTable(
        ["Bug", "Causa", "Solución"],
        [
          ["'Invalid stops' en modificación de SL", "SL demasiado cerca del precio actual", "Verificar STOPS_LEVEL + FREEZE_LEVEL antes de modify. Usar loop de reintentos."],
          ["Lote calculado incorrectamente", "Hardcodeo de TickValue o Point", "Usar SymbolInfoDouble() siempre. Imprimir diagnóstico en OnInit()."],
          ["EA no entra en backtest", "InpBrokerGMT incorrecto → sesión no coincide", "Agregar log de hora en cada tick durante debugging. Verificar offset."],
          ["CSV vacío en backtest", "OnTradeTransaction no se dispara en Strategy Tester", "Implementar polling con HistorySelect() en OnTick()"],
          ["Lotes exceden margen disponible", "No se verifica margen antes de abrir", "Loop de reducción de lote hasta que el margen disponible sea suficiente con buffer 15%."],
          ["Operaciones en días no deseados", "Filtro de día sin verificar correctamente", "Usar DayOfWeek() con hora del broker, no del sistema."],
        ],
