      // ══════════════════════════════════════════════════════════
      // 7. GESTIÓN DE RIESGO PROP FIRMS
      // ══════════════════════════════════════════════════════════
      h1("7. Gestión de Riesgo para Prop Firms (FundingPips)"),

      body("Las reglas de las Prop Firms son restricciones duras, no sugerencias. Violarlas invalida la cuenta. El EA debe tener estas restricciones integradas en el código, no solo en los parámetros."),
      ...sp(),

      h3("7.1  Reglas de FundingPips — 2 Phase Challenge"),
      makeTable(
        ["Parámetro", "Fase 1 (Challenge)", "Fase 2 (Verification)", "Cuenta Fondada"],
        [
          ["Profit Target", "8% del capital", "5% del capital", "No aplica"],
          ["Max Daily Drawdown", "5% del capital inicial", "5% del capital inicial", "5% del capital inicial"],
          ["Max Total Drawdown", "10% del capital inicial", "10% del capital inicial", "10% del capital inicial"],
          ["Tiempo mínimo", "No aplica", "No aplica", "No aplica"],
          ["Días mínimos de trading", "3 días", "3 días", "No aplica"],
          ["Tiempo máximo", "Ilimitado", "Ilimitado", "No aplica"],
          ["Instrumentos", "Todos los disponibles", "Todos los disponibles", "Todos los disponibles"],
        ],
        [2760, 2200, 2200, 2200]
      ),
      ...sp(),

      h3("7.2  Implementación del monitor de drawdown en el EA"),
      codeBox([
        "// Monitor de Drawdown — corre PRIMERO en cada OnTick()",
        "void CheckDrawdownLimits()",
        "{",
        "   double balance  = AccountInfoDouble(ACCOUNT_BALANCE);",
        "   double equity   = AccountInfoDouble(ACCOUNT_EQUITY);",
        "   double startBal = InpStartingBalance; // Capital inicial del challenge",
        "",
        "   // Drawdown diario: pérdida desde el balance de inicio del día",
        "   double dailyDD  = (g_dayStartBalance - equity) / startBal * 100.0;",
        "",
        "   // Drawdown total: pérdida desde el capital inicial",
        "   double totalDD  = (startBal - equity) / startBal * 100.0;",
        "",
        "   // Soft stop: bloquear nuevas entradas al 4% DD diario",
        "   if(dailyDD >= InpSoftDDLimit) g_tradingBlocked = true;",
        "",
        "   // Hard stop: cerrar TODO al 4.8% DD diario (buffer antes del límite de 5%)",
        "   if(dailyDD >= InpHardDDLimit || totalDD >= 9.5)",
        "   {",
        "      CloseAllPositions();",
        "      g_tradingBlocked = true;",
        "   }",
        "}",
      ]),
      ...sp(),

      h3("7.3  Parámetros de riesgo recomendados por tamaño de cuenta"),
      makeTable(
        ["Tamaño de cuenta", "Riesgo por trade recomendado", "Max trades/día", "RR mínimo", "Target diario realista"],
        [
          ["$5,000", "$25–$37 (0.5–0.75%)", "1", "1.5:1", "0.5–1% diario"],
          ["$10,000", "$50–$75 (0.5–0.75%)", "1", "1.5:1", "0.5–1% diario"],
          ["$25,000", "$125–$187 (0.5–0.75%)", "1", "1.5:1", "0.5–1% diario"],
          ["$50,000", "$250–$375 (0.5–0.75%)", "1", "2:1", "0.4–0.8% diario"],
          ["$100,000", "$500–$750 (0.5–0.75%)", "1", "2:1", "0.3–0.6% diario"],
        ],
        [1800, 2400, 1400, 1360, 2400]
      ),
      ...sp(),

      warnBox("Nunca usar riesgo > 1% por operación en una Prop Firm. Con un racha de 5 pérdidas consecutivas (estadísticamente normal), el 1% de riesgo por trade consume 5% del capital — exactamente el límite de drawdown diario."),
      ...sp(),

      h3("7.4  Cálculo de lotes correcto — Código universal MQL5"),
      codeBox([
        "double CalcLots(double slPoints, double riskUSD)",
        "{",
        "   double tickVal  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);",
        "   double tickSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);",
        "   double point    = SymbolInfoDouble(_Symbol, SYMBOL_POINT);",
        "   double volMin   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);",
        "   double volStep  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);",
        "   double volMax   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);",
        "",
        "   // Valor por punto por lote estándar",
        "   double valPerPoint = tickVal / tickSize * point;",
        "",
        "   // Lotes necesarios para arriesgar exactamente riskUSD",
        "   double lots = riskUSD / (slPoints * valPerPoint);",
        "",
        "   // Normalizar al step del broker",
        "   lots = MathFloor(lots / volStep) * volStep;",
        "   lots = MathMax(volMin, MathMin(volMax, lots));",
        "",
        "   // Verificar margen disponible con buffer 15%",
        "   double marginReq = 0;",
        "   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, SymbolInfoDouble(_Symbol,SYMBOL_ASK), marginReq))",
        "      return volMin;",
        "   if(marginReq * 1.15 > AccountInfoDouble(ACCOUNT_MARGIN_FREE))",
        "      lots = MathMax(volMin, lots * 0.8);",
        "",
        "   return lots;",
        "}",
      ]),
      ...sp(2),

      // ══════════════════════════════════════════════════════════
      // 8. BACKTESTING Y DIAGNÓSTICO
      // ══════════════════════════════════════════════════════════
      h1("8. Backtesting y Diagnóstico"),

      body("El backtesting es una herramienta de diagnóstico, no de confirmación. El objetivo es encontrar problemas, no celebrar resultados."),
      ...sp(),

      h3("8.1  Configuración del Strategy Tester"),
      makeTable(
        ["Parámetro", "Valor recomendado", "Por qué"],
        [
          ["Modelo", "Every tick based on real ticks", "Máxima fidelidad. Evitar 'OHLC on M1'."],
          ["Spread", "Real (del broker) o conservador (+20%)", "Evitar optimismo por spread irreal"],
          ["Período", "Mínimo 3 años, máximo disponible", "Validez estadística y diferentes regímenes"],
          ["Capital inicial", "Igual al challenge de la Prop Firm", "Resultados aplicables directamente"],
          ["Depósitos/retiros", "Ninguno", "Backtest limpio"],
        ],
        [2000, 3000, 4360]
      ),
      ...sp(),

      h3("8.2  Protocolo de diagnóstico cuando el backtest falla"),

      stepCard("D1", "Verificar que el EA entra operaciones", [
        "Si hay 0 trades: problema de configuración de sesión (hora del broker) o filtros demasiado restrictivos",
        "Agregar Print() en cada condición de entrada para ver por qué no se activa",
      ]),
      ...sp(),
      stepCard("D2", "Analizar distribución de salidas", [
        "Si >70% de salidas son por SL: el SL es muy corto, o la señal es débil",
        "Si >80% de salidas son por sesión: el TP es inalcanzable en el tiempo de operación",
        "Si muchas salidas son por BE (break-even): el buffer de BE está demasiado ajustado",
      ]),
      ...sp(),
      stepCard("D3", "Analizar por dirección", [
        "Separar resultados de LONG vs SHORT",
        "Si una dirección destruye el PF: deshabilitar esa dirección y re-testear",
        "Recuerda el sesgo estructural del activo (ej. NAS100 tiene sesgo alcista secular)",
      ]),
      ...sp(),
      stepCard("D4", "Analizar por día de semana y hora", [
        "Calcular PF por día: Lunes, Martes, Miércoles, Jueves, Viernes",
        "Días con PF < 1.0 son candidatos a filtrar",
        "Verificar que el filtro mejora el PF general y no solo reduce operaciones",
      ]),
      ...sp(),
      stepCard("D5", "Test de robustez de parámetros", [
        "Variar el parámetro principal ±20% y verificar que el PF se mantiene > 1.3",
        "Si el PF colapsa con variaciones pequeñas → es overfitting, no edge real",
        "Un edge real muestra curva suave de rendimiento vs parámetro, no un pico aislado",
      ]),
      ...sp(2),

      // ══════════════════════════════════════════════════════════
      // 9. ANTI-PATRONES PROHIBIDOS
      // ══════════════════════════════════════════════════════════
      h1("9. Anti-patrones Prohibidos"),

      body("Estos son los errores metodológicos más comunes que producen EAs que parecen rentables en backtest pero fallan en producción. Claude debe detectarlos activamente y alertar al usuario."),
      ...sp(),

      makeTable(
        ["Anti-patrón", "Descripción", "Consecuencia", "Cómo detectarlo"],
        [
          ["Optimismo prematuro", "Concluir viabilidad antes de analizar los datos reales del CSV", "El EA falla inmediatamente en producción", "Si se habla de 'potencial' sin datos duros → alerta"],
          ["Data snooping", "Probar cientos de parámetros y quedarse con el mejor", "El 'mejor' parámetro es ruido, no señal", "Test de robustez: ±20% debe mantener PF > 1.3"],
          ["Complejidad compensatoria", "Agregar trailing, filtros y módulos para arreglar un edge débil", "Sistema frágil que falla con cualquier cambio de mercado", "Si el EA base no es rentable, no agregar complejidad"],
          ["Ignorar costos reales", "Calcular RR sin incluir spread y comisión", "El sistema es rentable en papel pero perdedor en real", "Siempre calcular RR neto = (TP − Spread) ÷ (SL + Spread)"],
          ["In-sample exclusivo", "Optimizar y validar en los mismos datos", "El EA está sobreajustado al período de prueba", "Reservar 30% de datos como out-of-sample desde el inicio"],
          ["Ignorar sesgo del activo", "Operar LONG y SHORT en activos con sesgo unidireccional", "Una dirección destruye el PF sistémicamente", "Analizar rendimiento separado por dirección siempre"],
          ["Muestra insuficiente", "Validar con menos de 200 operaciones", "Alta varianza estadística, conclusiones inválidas", "Si N < 200, alargar el período o cambiar de activo"],
        ],
        [2000, 2600, 2200, 2560]
      ),
      ...sp(2),

      // ══════════════════════════════════════════════════════════
      // 10. PROMPT DE ARRANQUE
      // ══════════════════════════════════════════════════════════
      h1("10. Prompt de Arranque — Copiar y Pegar"),

      body("Usar este bloque completo al inicio de cada nueva conversación. Completar los campos entre corchetes antes de pegar."),
      ...sp(),

      codeBox([
        "═══════════════════════════════════════════════════════════",
        "  PROMPT MAESTRO v2.0 — TRADING CUANTITATIVO MQL5",
        "═══════════════════════════════════════════════════════════",
        "",
        "Eres un experto en trading cuantitativo, estadística financiera",
        "y programación avanzada en MQL5 para MetaTrader 5.",
        "",
        "IDENTIDAD:",
        "Tienes experiencia desarrollando EAs rentables para Prop Firms.",
        "Tu metodología es rigurosa, honesta y basada en evidencia real.",
        "",
        "REGLAS NO NEGOCIABLES:",
        "1. No concluyas viabilidad sin datos reales del CSV.",
        "2. No escribas código de EA hasta verificar edge estadístico.",
        "3. Muestra debilidades ANTES que fortalezas en el análisis.",
        "4. Si el backtest falla, diagnostica ANTES de agregar complejidad.",
        "5. Valida en out-of-sample antes de agregar módulos extra.",
        "6. Calcula siempre el RR NETO (post spread y comisión).",
        "7. Analiza rendimiento LONG vs SHORT por separado siempre.",
        "8. Aplica test de robustez: parámetro ±20% debe mantener PF>1.3.",
        "",
        "PROP FIRM OBJETIVO: FundingPips 2-Phase",
        "  - Max Daily DD: 5% del capital inicial",
        "  - Max Total DD: 10% del capital inicial",
        "  - Profit Target Fase 1: 8%",
        "  - Profit Target Fase 2: 5%",
        "",
        "PARÁMETROS DE LA CUENTA:",
        "  - Capital: [ej. $10,000]",
        "  - Riesgo por trade: [ej. $75 — 0.75%]",
        "  - Broker: [ej. FundingPips]",
