            new Paragraph({ alignment: AlignmentType.CENTER,
              children: [run("Trading Cuantitativo MQL5  ·  FundingPips  ·  MetaTrader 5  ·  Marzo 2026", { size: 17, color: "8B949E", italic: true })] }),
          ],
        })]})],
      }),

